tools = [
    {
        "name": "get_weather",
        "description": "Get current weather",
        "input_schema": {...}
    },
    {
        "name": "search_web",
        "description": "Search the web",
        "input_schema": {...},
        "cache_control": {"type": "ephemeral"}  # ✅ Breakpoint on last tool
    }
]

# Start with cached tools (always-loaded)
tools = [
    {
        "name": "get_weather",
        "defering": True,  # ❌ Deferred
        "input_schema": {...}
    },
    {
        "name": "search_web",
        "input_schema": {...},
        "cache_control": {"type": "ephemeral"}  # ✅ Breakpoint
    }
]

# Model discovers deferred tool via tool search
# → Definition appended as tool_reference inline
# → Prefix untouched, cache preserved

# If you need to vary tool_choice mid-conversation:
# Place cache breakpoint BEFORE the variation point

messages = [
    {
        "role": "user",
        "content": [
            {
                "type": "text",
                "text": "First part",
                "cache_control": {"type": "ephemeral"}  # ✅ Breakpoint before variation
            }
        ]
    },
    # tool_choice varies here (doesn't break cache)
]

# Re-sends everything every turn
for turn in conversation:
    messages = [
        {
            "role": "system",
            "content": large_system_prompt + large_codebase + turn.question
        }
    ]
    tools = [get_weather, search_web, ...]
    response = client.messages.create(model="...", messages=messages, tools=tools)

# Cache system + codebase once
messages = [
    {
        "role": "system",
        "content": [
            {
                "type": "text",
                "text": large_system_prompt,
                "cache_control": {"type": "ephemeral"}  # ✅ Cache 1
            },
            {
                "type": "text",
                "text": large_codebase,
                "cache_control": {"type": "ephemeral"}  # ✅ Cache 2
            }
        ]
    }
]

# Cache tools
tools = [
    {
        "name": "get_weather",
        "input_schema": {...}
    },
    {
        "name": "search_web",
        "input_schema": {...},
        "cache_control": {"type": "ephemeral"}  # ✅ Cache 3
    }
]

# Add dynamic question (not cached)
for turn in conversation:
    messages[0]["content"].append({
        "type": "text",
        "text": turn.question  # ❌ Not cached (dynamic)
    })
    response = client.messages.create(model="...", messages=messages, tools=tools)
